import asyncio
import json
import logging
import uuid
from dataclasses import dataclass, field
from typing import Dict, Optional, Set, Any

import websockets
from websockets.server import WebSocketServerProtocol

logging.basicConfig(level=logging.INFO)


@dataclass
class Item:
    item_id: str
    owner_id: str
    name: str
    quantity: int = 1
    metadata: Dict[str, Any] = field(default_factory=dict)


@dataclass
class Player:
    player_id: str
    ws: Optional[WebSocketServerProtocol] = None
    inventory: Set[str] = field(default_factory=set)
    balance: int = 0


class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.player_locks: Dict[str, asyncio.Lock] = {}
        self.global_lock = asyncio.Lock()

    def _get_player_lock(self, player_id: str) -> asyncio.Lock:
        if player_id not in self.player_locks:
            self.player_locks[player_id] = asyncio.Lock()
        return self.player_locks[player_id]

    async def _send(self, player_id: str, message: Dict[str, Any]):
        player = self.players.get(player_id)
        if player and player.ws:
            try:
                await player.ws.send(json.dumps(message))
            except Exception as e:
                logging.warning("Failed to send to %s: %s", player_id, e)

    async def register(self, ws: WebSocketServerProtocol, player_id: str):
        async with self.global_lock:
            player = self.players.get(player_id)
            if not player:
                player = Player(player_id=player_id, ws=ws)
                self.players[player_id] = player
            else:
                player.ws = ws
        await self._send(player_id, {"type": "welcome", "player_id": player_id})

    async def unregister(self, player_id: str):
        async with self.global_lock:
            player = self.players.get(player_id)
            if player:
                player.ws = None

    async def create_item(self, owner_id: str, name: str, quantity: int = 1, metadata: Optional[Dict[str, Any]] = None) -> Item:
        item = Item(
            item_id=str(uuid.uuid4()),
            owner_id=owner_id,
            name=name,
            quantity=quantity,
            metadata=metadata or {},
        )
        async with self.global_lock:
            self.items[item.item_id] = item
            if owner_id not in self.players:
                self.players[owner_id] = Player(player_id=owner_id)
            self.players[owner_id].inventory.add(item.item_id)
        return item

    async def get_inventory(self, player_id: str):
        async with self.global_lock:
            player = self.players.get(player_id)
            if not player:
                return []
            return [
                {
                    "item_id": item_id,
                    "name": self.items[item_id].name,
                    "quantity": self.items[item_id].quantity,
                    "owner_id": self.items[item_id].owner_id,
                    "metadata": self.items[item_id].metadata,
                }
                for item_id in player.inventory
                if item_id in self.items
            ]

    async def transfer_item(self, from_id: str, to_id: str, item_id: str, quantity: int = 1) -> Dict[str, Any]:
        if quantity <= 0:
            return {"ok": False, "error": "invalid_quantity"}

        lock_a = self._get_player_lock(from_id)
        lock_b = self._get_player_lock(to_id)

        first, second = (lock_a, lock_b) if from_id <= to_id else (lock_b, lock_a)

        async with first:
            async with second:
                async with self.global_lock:
                    item = self.items.get(item_id)
                    if not item:
                        return {"ok": False, "error": "item_not_found"}
                    if item.owner_id != from_id:
                        return {"ok": False, "error": "not_owner"}
                    if from_id not in self.players:
                        return {"ok": False, "error": "source_player_not_found"}
                    if to_id not in self.players:
                        self.players[to_id] = Player(player_id=to_id)

                    if item.quantity < quantity:
                        return {"ok": False, "error": "insufficient_quantity"}

                    source_player = self.players[from_id]
                    target_player = self.players[to_id]

                    if item.quantity == quantity:
                        source_player.inventory.discard(item_id)
                        target_player.inventory.add(item_id)
                        item.owner_id = to_id
                    else:
                        item.quantity -= quantity
                        new_item = Item(
                            item_id=str(uuid.uuid4()),
                            owner_id=to_id,
                            name=item.name,
                            quantity=quantity,
                            metadata=dict(item.metadata),
                        )
                        self.items[new_item.item_id] = new_item
                        target_player.inventory.add(new_item.item_id)

                await self._send(from_id, {"type": "item_transferred", "item_id": item_id, "to": to_id, "quantity": quantity})
                await self._send(to_id, {"type": "item_received", "item_id": item_id, "from": from_id, "quantity": quantity})
                return {"ok": True}

    async def handle_message(self, ws: WebSocketServerProtocol, player_id: str, raw: str):
        try:
            data = json.loads(raw)
        except json.JSONDecodeError:
            await ws.send(json.dumps({"type": "error", "error": "invalid_json"}))
            return

        msg_type = data.get("type")
        if msg_type == "inventory":
            inv = await self.get_inventory(player_id)
            await ws.send(json.dumps({"type": "inventory", "items": inv}))
        elif msg_type == "create_item":
            name = data.get("name")
            quantity = int(data.get("quantity", 1))
            metadata = data.get("metadata") or {}
            if not name:
                await ws.send(json.dumps({"type": "error", "error": "missing_name"}))
                return
            item = await self.create_item(player_id, name, quantity, metadata)
            await ws.send(json.dumps({"type": "item_created", "item": {
                "item_id": item.item_id,
                "name": item.name,
                "quantity": item.quantity,
                "owner_id": item.owner_id,
                "metadata": item.metadata,
            }}))
        elif msg_type == "transfer":
            to_id = data.get("to")
            item_id = data.get("item_id")
            quantity = int(data.get("quantity", 1))
            if not to_id or not item_id:
                await ws.send(json.dumps({"type": "error", "error": "missing_fields"}))
                return
            result = await self.transfer_item(player_id, to_id, item_id, quantity)
            await ws.send(json.dumps({"type": "transfer_result", **result}))
        else:
            await ws.send(json.dumps({"type": "error", "error": "unknown_message_type"}))


game_server = GameServer()


async def handler(ws: WebSocketServerProtocol):
    player_id = None
    try:
        first = await ws.recv()
        try:
            hello = json.loads(first)
        except json.JSONDecodeError:
            await ws.send(json.dumps({"type": "error", "error": "expected_hello"}))
            return

        if hello.get("type") != "hello" or not hello.get("player_id"):
            await ws.send(json.dumps({"type": "error", "error": "expected_hello"}))
            return

        player_id = str(hello["player_id"])
        await game_server.register(ws, player_id)

        async for raw in ws:
            await game_server.handle_message(ws, player_id, raw)
    except websockets.ConnectionClosed:
        pass
    except Exception as e:
        logging.exception("Handler error: %s", e)
    finally:
        if player_id:
            await game_server.unregister(player_id)


